operation.add:
// OpenCart Filter: make the module edit route available even when the marketplace install cache was not rebuilt yet.
if (is_dir(DIR_EXTENSION . 'AJAXaf/')) {
	$this->autoloader->register('Opencart\Admin\Controller\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/admin/controller/');
	$this->autoloader->register('Opencart\Admin\Model\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/admin/model/');
	$this->autoloader->register('Opencart\System\Library\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/system/library/');
	$this->template->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/admin/view/template/');
	$this->language->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/admin/language/');
	$this->config->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/system/config/');
}

// OpenCart Filter: make storefront AJAX routes available even when the marketplace install cache was not rebuilt yet.
if (is_dir(DIR_EXTENSION . 'AJAXaf/')) {
	$this->autoloader->register('Opencart\Catalog\Controller\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/catalog/controller/');
	$this->autoloader->register('Opencart\Catalog\Model\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/catalog/model/');
	$this->autoloader->register('Opencart\System\Library\Extension\AJAXaf', DIR_EXTENSION . 'AJAXaf/system/library/');
	$this->template->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/catalog/view/template/');
	$this->language->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/catalog/language/');
	$this->config->addPath('extension/AJAXaf', DIR_EXTENSION . 'AJAXaf/system/config/');
}
